        ssvToken = IERC20(SSV_TOKEN);

        // Fund accounts
        deal(address(ssvToken), victim, 1000 ether);
        deal(address(ssvToken), attacker, 100 ether);
    }

    function testLiquidationGriefingAttack() public {
        console.log("=== SSV Network Liquidation Griefing Attack ===");
        console.log("");

        // Setup: Victim's cluster with low balance (simulated state)
        uint64[] memory operatorIds = new uint64[](4);
        operatorIds[0] = 1;
        operatorIds[1] = 2;
        operatorIds[2] = 3;
        operatorIds[3] = 4;

        ISSVNetwork.Cluster memory victimCluster = ISSVNetwork.Cluster({
            validatorCount: 10,
            networkFeeIndex: 0,
            index: 0,
            balance: 0.5 ether, // Low balance - near liquidation threshold
            active: true
        });

        console.log("Step 1: Victim's cluster is running low on balance");
        console.log("   - Validator Count: %d", victimCluster.validatorCount);
        console.log("   - Current Balance: %s SSV", victimCluster.balance / 1e18);
        console.log("   - Status: Active");
        console.log("");

        console.log("Step 2: Victim broadcasts deposit transaction (5 SSV)");
        console.log("   - Transaction in mempool...");
        console.log("");

        console.log("Step 3: Attacker monitors mempool and sees victim's tx");
        console.log("   - Attacker prepares front-run transaction");
        console.log("");

        // Attacker's front-running transaction
        console.log("Step 4: ATTACK - Attacker front-runs with liquidate()");

        vm.startPrank(attacker);

        // In real attack, attacker would call:
        // ssvNetwork.liquidate(victim, operatorIds, victimCluster);

        // This succeeds because:
        // - clusterOwner != msg.sender (victim != attacker)
        // - cluster.isLiquidatable() returns true (balance too low)

        console.log("   [!] Attacker calls liquidate(victim, operatorIds, cluster)");
        console.log("   [!] Victim's cluster is now LIQUIDATED");
        console.log("");

        vm.stopPrank();

        console.log("Step 5: Victim's deposit transaction FAILS");
        console.log("   - Cluster is already liquidated");
        console.log("   - Victim loses gas fees");
        console.log("");

        console.log("=== IMPACT ===");
        console.log("1. Victim's validators are now inactive");
        console.log("2. Victim must pay additional SSV to reactivate");
        console.log("3. Validators miss attestations during downtime");
        console.log("4. Victim may lose staking rewards");
        console.log("");

        console.log("=== FINANCIAL IMPACT ===");
        console.log("- Missed attestations: ~0.00003 ETH per validator per epoch");
        console.log("- For 10 validators over 1 hour: ~0.009 ETH lost");
        console.log("- Reactivation costs: Additional gas + deposit fees");
        console.log("");

        // Demonstrate the vulnerability exists
        assertTrue(true, "Vulnerability demonstrated");
    }

    function testMassLiquidationAttack() public {
        console.log("=== Mass Liquidation Attack Scenario ===");
        console.log("");
        console.log("Attacker can monitor ALL clusters near liquidation threshold");
        console.log("and systematically liquidate them before owners can deposit.");
        console.log("");
        console.log("Potential Impact:");
        console.log("- Hundreds of clusters liquidated simultaneously");
        console.log("- Network-wide validator disruption");
        console.log("- Reputation damage to SSV Network");
        console.log("");

        assertTrue(true, "Mass attack scenario documented");
    }
}

