        console.log("   - Current Balance: %s SSV", victimCluster.balance / 1e18);
        console.log("   - Status: Active");
        console.log("");

        console.log("Step 2: Victim broadcasts deposit transaction (5 SSV)");
        console.log("   - Transaction in mempool...");
        console.log("");

        console.log("Step 3: Attacker monitors mempool and sees victim's tx");
        console.log("   - Attacker prepares front-run transaction");
        console.log("");

